entrypoint function finalize(
        datasig oracle_sig,
        byte[32] oracle_seed,
        int winner_ticket_id,
        pubkey winner_pubkey,
        pubkey caller_pubkey
    ) {
        require(OpAuthOutputCount(this.activeInputIndex) == 0);
        require(tx.inputs.length == 2);
        require(tx.inputs[1].scriptPubKey == byte[](new ScriptPubKeyP2PK(caller_pubkey)));
        require(sold_tickets > 0);
        require(sold_batches > 0);
        require(sold_tickets == max_tickets || tx.locktime >= refund_after_daa);
        require(checkSigFromStack(oracle_sig, sha256(byte[](oracle_seed)), pubkey(oracle_pubkey)));

        byte[32] caller = byte[32](caller_pubkey);
        bool caller_is_participant = caller == owner_01;
        if (sold_batches >= 2 && caller == owner_02) { caller_is_participant = true; }
        if (sold_batches >= 3 && caller == owner_03) { caller_is_participant = true; }
        if (sold_batches >= 4 && caller == owner_04) { caller_is_participant = true; }
        if (sold_batches >= 5 && caller == owner_05) { caller_is_participant = true; }
        if (sold_batches >= 6 && caller == owner_06) { caller_is_participant = true; }
        if (sold_batches >= 7 && caller == owner_07) { caller_is_participant = true; }
        if (sold_batches >= 8 && caller == owner_08) { caller_is_participant = true; }
        if (sold_batches >= 9 && caller == owner_09) { caller_is_participant = true; }
        if (sold_batches >= 10 && caller == owner_10) { caller_is_participant = true; }
        if (sold_batches >= 11 && caller == owner_11) { caller_is_participant = true; }
        if (sold_batches >= 12 && caller == owner_12) { caller_is_participant = true; }
        if (sold_batches >= 13 && caller == owner_13) { caller_is_participant = true; }
        if (sold_batches >= 14 && caller == owner_14) { caller_is_participant = true; }
        if (sold_batches >= 15 && caller == owner_15) { caller_is_participant = true; }
        if (sold_batches >= 16 && caller == owner_16) { caller_is_participant = true; }
        if (sold_batches >= 17 && caller == owner_17) { caller_is_participant = true; }
        if (sold_batches >= 18 && caller == owner_18) { caller_is_participant = true; }
        if (sold_batches >= 19 && caller == owner_19) { caller_is_participant = true; }
        if (sold_batches >= 20 && caller == owner_20) { caller_is_participant = true; }
        require(caller_is_participant);

        byte[32] seed = sha256(byte[](ticket_root) + byte[](oracle_seed));
        int seed_0 = int(seed[0]);
        int seed_1 = int(seed[1]);
        int seed_2 = int(seed[2]);
        int seed_3 = int(seed[3]);
        if (seed_0 < 0) {
            seed_0 = -seed_0;
        }
        if (seed_1 < 0) {
            seed_1 = -seed_1;
        }
        if (seed_2 < 0) {
            seed_2 = -seed_2;
        }
        if (seed_3 < 0) {
            seed_3 = -seed_3;
        }

        int winner_from_seed = (seed_0 + seed_1 * 128 + seed_2 * 16384 + seed_3 * 2097152) % sold_tickets;
        require(winner_ticket_id < sold_tickets);
        require(winner_ticket_id == winner_from_seed);

        byte[32] winner_owner = owner_01;
        if (sold_batches >= 2 && winner_from_seed >= batch_end_01) {
            winner_owner = owner_02;
        }
        if (sold_batches >= 3 && winner_from_seed >= batch_end_02) {
            winner_owner = owner_03;
        }
        if (sold_batches >= 4 && winner_from_seed >= batch_end_03) {
            winner_owner = owner_04;
        }
        if (sold_batches >= 5 && winner_from_seed >= batch_end_04) {
            winner_owner = owner_05;
        }
        if (sold_batches >= 6 && winner_from_seed >= batch_end_05) {
            winner_owner = owner_06;
        }
        if (sold_batches >= 7 && winner_from_seed >= batch_end_06) {
            winner_owner = owner_07;
        }
        if (sold_batches >= 8 && winner_from_seed >= batch_end_07) {
            winner_owner = owner_08;
        }
        if (sold_batches >= 9 && winner_from_seed >= batch_end_08) {
            winner_owner = owner_09;
        }
        if (sold_batches >= 10 && winner_from_seed >= batch_end_09) {
            winner_owner = owner_10;
        }
        if (sold_batches >= 11 && winner_from_seed >= batch_end_10) {
            winner_owner = owner_11;
        }
        if (sold_batches >= 12 && winner_from_seed >= batch_end_11) {
            winner_owner = owner_12;
        }
        if (sold_batches >= 13 && winner_from_seed >= batch_end_12) {
            winner_owner = owner_13;
        }
        if (sold_batches >= 14 && winner_from_seed >= batch_end_13) {
            winner_owner = owner_14;
        }
        if (sold_batches >= 15 && winner_from_seed >= batch_end_14) {
            winner_owner = owner_15;
        }
        if (sold_batches >= 16 && winner_from_seed >= batch_end_15) {
            winner_owner = owner_16;
        }
        if (sold_batches >= 17 && winner_from_seed >= batch_end_16) {
            winner_owner = owner_17;
        }
        if (sold_batches >= 18 && winner_from_seed >= batch_end_17) {
            winner_owner = owner_18;
        }
        if (sold_batches >= 19 && winner_from_seed >= batch_end_18) {
            winner_owner = owner_19;
        }
        if (sold_batches >= 20 && winner_from_seed >= batch_end_19) {
            winner_owner = owner_20;
        }
        require(byte[32](winner_pubkey) == winner_owner);

        int prize = ticket_price * sold_tickets;
        int creator_refund = tx.inputs[this.activeInputIndex].value - prize - 2000000;
        require(creator_refund >= 0);
        require(tx.outputs.length == 3);
        require(tx.outputs[0].scriptPubKey == byte[](new ScriptPubKeyP2PK(winner_pubkey)));
        require(tx.outputs[0].value == prize);
        require(tx.outputs[1].scriptPubKey == byte[](new ScriptPubKeyP2PK(pubkey(creator_pubkey))));
        require(tx.outputs[1].value == creator_refund);
        require(tx.outputs[2].scriptPubKey == byte[](new ScriptPubKeyP2PK(caller_pubkey)));
        require(tx.outputs[2].value == tx.inputs[1].value);
    }

