    entrypoint function close() {
        require(OpAuthOutputCount(this.activeInputIndex) == 1);
        int cov_out_idx = OpAuthOutputIdx(this.activeInputIndex, 0);
        require(sold_tickets > 0);
        require(tx.outputs[cov_out_idx].scriptPubKey == tx.inputs[this.activeInputIndex].scriptPubKey);
        require(tx.outputs[cov_out_idx].value >= ticket_price * sold_tickets);
    }

    entrypoint function finalize(
        datasig oracle_sig,
        byte[32] oracle_seed,
        int winner_ticket_id,
        pubkey winner_pubkey,
        pubkey caller_pubkey
    ) {
        require(OpAuthOutputCount(this.activeInputIndex) == 0);
        require(tx.inputs.length == 2);
        require(tx.inputs[1].scriptPubKey == byte[](new ScriptPubKeyP2PK(caller_pubkey)));
        require(sold_tickets > 0);
        require(sold_batches > 0);
        require(sold_tickets == max_tickets || tx.locktime >= refund_after_daa);
        require(checkSigFromStack(oracle_sig, sha256(byte[](oracle_seed)), pubkey(oracle_pubkey)));

        byte[32] caller = byte[32](caller_pubkey);
        bool caller_is_participant = caller == owner_01;
        if (sold_batches >= 2 && caller == owner_02) { caller_is_participant = true; }
        if (sold_batches >= 3 && caller == owner_03) { caller_is_participant = true; }
        if (sold_batches >= 4 && caller == owner_04) { caller_is_participant = true; }
        if (sold_batches >= 5 && caller == owner_05) { caller_is_participant = true; }
        if (sold_batches >= 6 && caller == owner_06) { caller_is_participant = true; }
        if (sold_batches >= 7 && caller == owner_07) { caller_is_participant = true; }
        if (sold_batches >= 8 && caller == owner_08) { caller_is_participant = true; }
        if (sold_batches >= 9 && caller == owner_09) { caller_is_participant = true; }
